async function validateMCPGeneratedToken(token: string): Promise<MCPAuthContext | null> {
  try {
    const secret = new TextEncoder().encode(MCP_TOKEN_SECRET)

    const { payload } = await jose.jwtVerify(token, secret, {
      issuer: "exolar-qa",
      audience: "mcp-client",
    })

    // Check if it's our MCP token
    if (payload.type !== "mcp") {
      return null
    }

    const userId = parseInt(payload.sub as string, 10)
    const email = payload.email as string
    const organizationId = payload.org_id as number
    const organizationSlug = payload.org_slug as string
    const orgRole = payload.org_role as "owner" | "admin" | "viewer"

    if (!userId || !email || !organizationId) {
      console.error("[mcp-auth] MCP token missing required claims")
      return null
    }

    // Get user role from database (not stored in token for security)
    const sql = getSql()
    const result = await sql`
      SELECT role as user_role FROM dashboard_users WHERE id = ${userId}
    `

    const userRole = result.length > 0 ? (result[0].user_role as "admin" | "viewer") : "viewer"

    return {
      userId,
      email,
      organizationId,
      organizationSlug,
      orgRole,
      userRole,
    }
  } catch {
    // Not a valid MCP token, will try Neon Auth next
    return null
  }
}

// Token validity: 30 days const TOKEN_VALIDITY_DAYS = 30
// ...
const expiresAt = new Date(Date.now() + TOKEN_VALIDITY_DAYS * 24 * 60 * 60 * 1000)
const token = await new jose.SignJWT({ sub: context.userId.toString(), email: context.email, org_id: context.organizationId, org_slug: context.organizationSlug, org_role: context.orgRole, type: "mcp", }) .setProtectedHeader({ alg: "HS256" }) .setIssuedAt() .setExpirationTime(expiresAt) .setIssuer("exolar-qa") .setAudience("mcp-client") .sign(secret)

function jsonResponse(data: unknown): ToolResponse {
  return {
    content: [{ type: "text", text: JSON.stringify(data, null, 2) }],
  }
}

solution.updated_validation_function:
async function validateMCPGeneratedToken(token: string): Promise<MCPAuthContext | null> {
  try {
    const secret = new TextEncoder().encode(MCP_TOKEN_SECRET)

    const { payload } = await jose.jwtVerify(token, secret, {
      issuer: "exolar-qa",
      audience: "mcp-client",
    })

    // Check if it's our MCP token
    if (payload.type !== "mcp") {
      return null
    }

    const userId = parseInt(payload.sub as string, 10)
    const email = payload.email as string
    const organizationId = payload.org_id as number
    const organizationSlug = payload.org_slug as string
    const orgRole = payload.org_role as "owner" | "admin" | "viewer"

    if (!userId || !email || !organizationId) {
      console.error("[mcp-auth] MCP token missing required claims")
      return null
    }

    // Get user role from database
    const sql = getSql()
    const result = await sql`
      SELECT role as user_role FROM dashboard_users WHERE id = ${userId}
    `
    const userRole = result.length > 0 ? (result[0].user_role as "admin" | "viewer") : "viewer"

    // NEW: Extract and calculate token expiry info
    let tokenExpiresAt: Date | null = null
    let tokenExpiresInDays: number | null = null
    let tokenRefreshWarning: 'none' | 'warning' | 'critical' | null = null

    if (payload.exp) {
      tokenExpiresAt = new Date(payload.exp * 1000)  // JWT exp is in seconds
      const now = new Date()
      const msRemaining = tokenExpiresAt.getTime() - now.getTime()
      tokenExpiresInDays = Math.floor(msRemaining / (1000 * 60 * 60 * 24))

      if (tokenExpiresInDays <= TOKEN_CRITICAL_DAYS) {
        tokenRefreshWarning = 'critical'
        console.warn(`[mcp-auth] Token expires in ${tokenExpiresInDays} days (CRITICAL) for user ${email}`)
      } else if (tokenExpiresInDays <= TOKEN_WARNING_DAYS) {
        tokenRefreshWarning = 'warning'
        console.warn(`[mcp-auth] Token expires in ${tokenExpiresInDays} days for user ${email}`)
      } else {
        tokenRefreshWarning = 'none'
      }
    }

    return {
      userId,
      email,
      organizationId,
      organizationSlug,
      orgRole,
      userRole,
      tokenExpiresAt,
      tokenExpiresInDays,
      tokenRefreshWarning,
    }
  } catch {
    return null
  }
}

solution.helper_function:
/**
 * Get token expiry warning metadata for tool responses
 */
export function getTokenExpiryMeta(context: MCPAuthContext): object | null {
  if (!context.tokenRefreshWarning || context.tokenRefreshWarning === 'none') {
    return null
  }

  const refreshCommand = 'npx @exolar-qa/mcp-server --login'

  if (context.tokenRefreshWarning === 'critical') {
    return {
      _warning: {
        type: 'token_expiry',
        severity: 'critical',
        message: `Token expires in ${context.tokenExpiresInDays} day(s). Run: ${refreshCommand}`,
        expiresAt: context.tokenExpiresAt?.toISOString(),
        expiresInDays: context.tokenExpiresInDays,
        refreshCommand,
      }
    }
  }

  return {
    _warning: {
      type: 'token_expiry',
      severity: 'warning',
      message: `Token expires in ${context.tokenExpiresInDays} days. Consider refreshing soon.`,
      expiresAt: context.tokenExpiresAt?.toISOString(),
      expiresInDays: context.tokenExpiresInDays,
      refreshCommand,
    }
  }
}

solution.updated_json_response:
// Option A: Modify jsonResponse to accept authContext and add warnings
function jsonResponse(data: unknown, authContext?: MCPAuthContext): ToolResponse {
  const response: Record<string, unknown> = data as Record<string, unknown>

  // Add expiry warning if applicable
  if (authContext) {
    const expiryMeta = getTokenExpiryMeta(authContext)
    if (expiryMeta) {
      Object.assign(response, expiryMeta)
    }
  }

  return {
    content: [{ type: "text", text: JSON.stringify(response, null, 2) }],
  }
}

// Then in handleToolCall, pass authContext to jsonResponse:
// return jsonResponse({ ... }, authContext)

solution.alternative_approach:
// Alternative: Create a wrapper that adds warnings without modifying jsonResponse
function withExpiryWarning(response: unknown, authContext: MCPAuthContext): unknown {
  if (typeof response !== 'object' || response === null) {
    return response
  }

  const expiryMeta = getTokenExpiryMeta(authContext)
  if (!expiryMeta) {
    return response
  }

  return { ...response, ...expiryMeta }
}

// Usage in handleToolCall:
const result = { organization: authContext.organizationSlug, ... }
return jsonResponse(withExpiryWarning(result, authContext))

